// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract GrandGooseMansion {
    address private _owner;
    uint256 public supply;
    uint256 public cost;
    uint256 public maxSupply;
    uint256 public preSaleWalletLimit;
    mapping(address => uint256) public preSaleWalletMinted;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus public currentSaleStatus;
    mapping(address => bool) private _whitelist;

    event Minted(address indexed minter, uint256 amount);

    bytes32 private constant _ENTERED = keccak256("ENTERED");
    bytes32 private constant _NOT_ENTERED = keccak256("NOT_ENTERED");
    bytes32 private _status = _NOT_ENTERED;

    modifier nonReentrant() {
        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    constructor(
        uint256 _initialSupply,
        uint256 _initialCost,
        uint256 _maxSupply,
        uint256 _preSaleWalletLimit
    ) {
        _owner = msg.sender;
        supply = _initialSupply;
        cost = _initialCost;
        maxSupply = _maxSupply;
        preSaleWalletLimit = _preSaleWalletLimit;
        currentSaleStatus = SaleStatus.Paused;
    }

    function isWhitelisted(address user) public view returns (bool) {
        return _whitelist[user];
    }

    function whitelistUser(address user, bool status) public onlyOwner {
        _whitelist[user] = status;
    }

    function startPresale() public onlyOwner {
        require(currentSaleStatus != SaleStatus.PublicSale, "Already in public sale");
        currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() public onlyOwner {
        require(currentSaleStatus == SaleStatus.Presale, "Not in presale");
        currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) public onlyOwner {
        cost = newCost;
    }

    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "New owner cannot be zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }

    function mintTokenWhitelisted(uint256 amount) public payable nonReentrant {
        require(currentSaleStatus == SaleStatus.Presale, "Presale not active");
        require(_whitelist[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds maximum supply");
        require(preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        preSaleWalletMinted[msg.sender] += amount;
        emit Minted(msg.sender, amount);
    }

    function mintTokenPublic(uint256 amount) public payable nonReentrant {
        require(currentSaleStatus == SaleStatus.PublicSale, "Public sale not active");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds maximum supply");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        emit Minted(msg.sender, amount);
    }
}
